import javax.naming.*;
import java.util.*;
import java.lang.reflect.*;

public class LdapUserSearch {
    public static Map<String, Object> searchUser(String username, String ldapUrl) throws NamingException {
        Hashtable<String, String> env = new Hashtable<>();
        env.put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
        env.put(Context.PROVIDER_URL, ldapUrl);
        env.put(Context.SECURITY_AUTHENTICATION, "simple"); // Change this to your authentication method if needed
        env.put(Context.SECURITY_PRINCIPAL, "<your-ldap-username>");
        env.put(Context.SECURITY_CREDENTIALS, "<your-ldap-password>");

        DirectoryContext ctx = new InitialDirContext(env);

        String searchBase = "dc=example,dc=com"; // Change this to your LDAP base DN
        String userSearchFilter = String.format("(&(objectClass=user)(uid=%s))", username);

        NamingEnumeration<SearchResult> results = ctx.search(searchBase, new Object[] { userSearchFilter }, new String[] { "*" });

        Map<String, Object> userAttributes = new HashMap<>();

        while (results.hasMore()) {
            SearchResult searchResult = results.next();
            Attributes attributes = searchResult.getAttributes();

            if (attributes != null) {
                Enumeration<?> attributeNames = attributes.getNames();
                while (attributeNames.hasMoreElements()) {
                    String attributeName = (String) attributeNames.nextElement();
                    Object attributeValue = attributes.get(attributeName);

                    if ("mail".equalsIgnoreCase(attributeName)) {
                        userAttributes.put("email", attributeValue);
                    } else if ("cn".equalsIgnoreCase(attributeName)) {
                        userAttributes.put("fullName", attributeValue);
                    } else if ("department".equalsIgnoreCase(attributeName)) {
                        userAttributes.put("department", attributeValue);
                    }
                }
            }
        }

        return userAttributes;
    }
}